package org.eclipse.rdf4j.http.server.repository;

import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Map;

import org.apache.http.HttpStatus;
import org.eclipse.rdf4j.common.webapp.util.HttpServerUtil;
import org.eclipse.rdf4j.http.protocol.Protocol;
import org.eclipse.rdf4j.query.explanation.Explanation;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;

public class ExplainQueryResultView extends QueryResultView {

	private static final String MIME_PLAIN = "text/plain";
	private static final String MIME_JSON = "application/json";
	private static final String UNSUPPORTED_MIME_TYPE_MESSAGE = "Must be either text/plain or application/json.";

	@Override
	protected void renderInternal(
			final Map model, final HttpServletRequest request, final HttpServletResponse response) throws IOException {

		String mimeType = getRequestedMimeType(request, response);
		Explanation explanation = (Explanation) model.get(QUERY_EXPLAIN_RESULT_KEY);
		String requestedMimeType = request.getParameter(Protocol.ACCEPT_PARAM_NAME);

		if (explanation == null) {
			response.sendError(HttpServletResponse.SC_BAD_REQUEST, "No explanation result found.");
			return;
		}

		if (!MIME_JSON.equals(mimeType) && !MIME_PLAIN.equals(mimeType)) {
			if (requestedMimeType != null) {
				response.sendError(HttpServletResponse.SC_BAD_REQUEST,
						"Unsupported MIME type: " + requestedMimeType + ". " + UNSUPPORTED_MIME_TYPE_MESSAGE);
			} else {
				response.sendError(HttpServletResponse.SC_NOT_ACCEPTABLE, UNSUPPORTED_MIME_TYPE_MESSAGE);
			}
			return;
		}

		response.setCharacterEncoding("UTF-8");
		response.setStatus(HttpStatus.SC_OK);
		response.setContentType(mimeType);

		try (PrintWriter writer = response.getWriter()) {
			writer.write(MIME_JSON.equals(mimeType) ? explanation.toJson() : explanation.toString());
		}
	}

	private String getRequestedMimeType(HttpServletRequest request, HttpServletResponse response) {
		String mimeType = request.getParameter(Protocol.ACCEPT_PARAM_NAME);
		if (mimeType != null) {
			return mimeType;
		}

		response.setHeader("Vary", "Accept");
		return HttpServerUtil.selectPreferredMIMEType(Arrays.asList(MIME_PLAIN, MIME_JSON).iterator(), request);
	}
}
